package com.example.mfa.mfa;

import org.springframework.stereotype.Component;

import java.security.SecureRandom;
import java.util.ArrayList;
import java.util.Base64;
import java.util.List;

@Component
public class BackupCodeGenerator {

    private final SecureRandom random = new SecureRandom();

    public List<String> generateCodes(int count) {
        List<String> codes = new ArrayList<>(count);
        for (int i = 0; i < count; i++) {
            codes.add(formatCode(randomBytes(10)));
        }
        return codes;
    }

    private byte[] randomBytes(int n) {
        byte[] b = new byte[n];
        random.nextBytes(b);
        return b;
    }

    private String formatCode(byte[] bytes) {
        String s = Base64.getUrlEncoder().withoutPadding().encodeToString(bytes).toUpperCase();
        if (s.length() < 16) {
            s = (s + "0000000000000000").substring(0, 16);
        } else if (s.length() > 16) {
            s = s.substring(0, 16);
        }
        return s.substring(0, 4) + "-" + s.substring(4, 8) + "-" + s.substring(8, 12) + "-" + s.substring(12, 16);
    }
}

package com.example.mfa.mfa;

import com.example.mfa.user.AppUser;
import com.example.mfa.user.UserRepository;
import jakarta.transaction.Transactional;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;

import java.time.Instant;
import java.util.List;
import java.util.stream.Collectors;

@Service
public class MfaBackupCodeService {

    private final MfaBackupCodeRepository repo;
    private final BackupCodeGenerator generator;
    private final PasswordEncoder encoder;
    private final UserRepository userRepository;

    public MfaBackupCodeService(MfaBackupCodeRepository repo,
                                BackupCodeGenerator generator,
                                PasswordEncoder encoder,
                                UserRepository userRepository) {
        this.repo = repo;
        this.generator = generator;
        this.encoder = encoder;
        this.userRepository = userRepository;
    }

    @Transactional
    public List<String> generateAndStoreNewCodesForUser(String username, int count) {
        AppUser user = userRepository.findByUsername(username).orElseThrow();
        repo.deleteAllByUser(user);

        List<String> plain = generator.generateCodes(count);
        List<MfaBackupCode> entities = plain.stream().map(code -> {
            MfaBackupCode c = new MfaBackupCode();
            c.setUser(user);
            c.setCodeHash(encoder.encode(normalize(code)));
            return c;
        }).collect(Collectors.toList());

        repo.saveAll(entities);
        return plain;
    }

    @Transactional
    public boolean consumeBackupCode(AppUser user, String providedCode, String ip, String ua) {
        String normalized = normalize(providedCode);
        List<MfaBackupCode> active = repo.findActiveByUser(user);
        for (MfaBackupCode c : active) {
            if (encoder.matches(normalized, c.getCodeHash())) {
                int updated = repo.markUsed(c.getId(), Instant.now(), ip, truncate(ua, 256));
                return updated == 1;
            }
        }
        return false;
    }

    private String normalize(String code) {
        if (code == null) return "";
        return code.replace("-", "").replace(" ", "").trim().toUpperCase();
    }

    private String truncate(String s, int max) {
        if (s == null) return null;
        return s.length() <= max ? s : s.substring(0, max);
    }
}

package com.example.mfa.mfa;

import org.springframework.stereotype.Component;

import javax.crypto.Mac;
import javax.crypto.spec.SecretKeySpec;
import java.nio.ByteBuffer;
import java.nio.charset.StandardCharsets;
import java.security.SecureRandom;
import java.time.Instant;
import java.util.Base64;

@Component
public class TotpService {

    private final SecureRandom random = new SecureRandom();

    public String generateSecret() {
        byte[] b = new byte[20];
        random.nextBytes(b);
        return Base64.getUrlEncoder().withoutPadding().encodeToString(b);
    }

    public boolean verifyCode(String secret, String code, int window) {
        if (secret == null || code == null) return false;
        String normalized = code.trim();
        if (!normalized.matches("\\d{6}")) return false;

        long nowStep = Instant.now().getEpochSecond() / 30;
        for (int i = -window; i <= window; i++) {
            String expected = generateTotp(secret, nowStep + i);
            if (constantTimeEquals(expected, normalized)) return true;
        }
        return false;
    }

    private String generateTotp(String secret, long timestep) {
        try {
            byte[] key = Base64.getUrlDecoder().decode(secret);
            byte[] msg = ByteBuffer.allocate(8).putLong(timestep).array();
            Mac mac = Mac.getInstance("HmacSHA1");
            mac.init(new SecretKeySpec(key, "HmacSHA1"));
            byte[] hash = mac.doFinal(msg);

            int offset = hash[hash.length - 1] & 0x0F;
            int binary =
                    ((hash[offset] & 0x7f) << 24) |
                            ((hash[offset + 1] & 0xff) << 16) |
                            ((hash[offset + 2] & 0xff) << 8) |
                            (hash[offset + 3] & 0xff);

            int otp = binary % 1_000_000;
            return String.format("%06d", otp);
        } catch (Exception e) {
            throw new IllegalStateException(e);
        }
    }

    private boolean constantTimeEquals(String a, String b) {
        byte[] x = a.getBytes(StandardCharsets.UTF_8);
        byte[] y = b.getBytes(StandardCharsets.UTF_8);
        int diff = x.length ^ y.length;
        for (int i = 0; i < Math.min(x.length, y.length); i++) diff |= x[i] ^ y[i];
        return diff == 0;
    }
}

package com.example.mfa.auth;

import com.example.mfa.mfa.MfaBackupCodeService;
import com.example.mfa.mfa.TotpService;
import com.example.mfa.security.AuthTokenService;
import com.example.mfa.user.AppUser;
import com.example.mfa.user.UserRepository;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.transaction.Transactional;
import org.springframework.security.authentication.AuthenticationManager;
import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
import org.springframework.security.core.Authentication;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;

import java.util.List;

@Service
public class AuthService {

    private final AuthenticationManager authenticationManager;
    private final UserRepository userRepository;
    private final PasswordEncoder passwordEncoder;
    private final TotpService totpService;
    private final MfaBackupCodeService backupCodeService;
    private final AuthTokenService tokenService;

    public AuthService(AuthenticationManager authenticationManager,
                       UserRepository userRepository,
                       PasswordEncoder passwordEncoder,
                       TotpService totpService,
                       MfaBackupCodeService backupCodeService,
                       AuthTokenService tokenService) {
        this.authenticationManager = authenticationManager;
        this.userRepository = userRepository;
        this.passwordEncoder = passwordEncoder;
        this.totpService = totpService;
        this.backupCodeService = backupCodeService;
        this.tokenService = tokenService;
    }

    @Transactional
    public void register(String username, String password) {
        if (userRepository.findByUsername(username).isPresent()) {
            throw new IllegalArgumentException("Username already exists");
        }
        AppUser u = new AppUser();
        u.setUsername(username);
        u.setPasswordHash(passwordEncoder.encode(password));
        userRepository.save(u);
    }

    public LoginResponse login(LoginRequest req) {
        Authentication auth = authenticationManager.authenticate(
                new UsernamePasswordAuthenticationToken(req.username(), req.password())
        );
        AppUser user = (AppUser) auth.getPrincipal();

        if (user.isMfaEnabled()) {
            String mfaToken = tokenService.issueToken(user.getUsername(), 300);
            return LoginResponse.mfaRequired(mfaToken);
        } else {
            String accessToken = tokenService.issueToken(user.getUsername(), 3600);
            return LoginResponse.success(accessToken);
        }
    }

    public VerifyMfaResponse verifyTotp(VerifyMfaRequest req) {
        String username = tokenService.parseUsername(req.mfaToken());
        if (username == null) throw new IllegalArgumentException("Invalid mfaToken");
        AppUser user = userRepository.findByUsername(username).orElseThrow();

        if (!user.isMfaEnabled()) throw new IllegalStateException("MFA not enabled");
        if (!totpService.verifyCode(user.getTotpSecret(), req.code(), 1)) {
            throw new IllegalArgumentException("Invalid TOTP code");
        }
        String accessToken = tokenService.issueToken(user.getUsername(), 3600);
        return new VerifyMfaResponse(accessToken);
    }

    public VerifyMfaResponse verifyBackupCode(VerifyBackupCodeRequest req, HttpServletRequest http) {
        String username = tokenService.parseUsername(req.mfaToken());
        if (username == null) throw new IllegalArgumentException("Invalid mfaToken");
        AppUser user = userRepository.findByUsername(username).orElseThrow();

        if (!user.isMfaEnabled()) throw new IllegalStateException("MFA not enabled");

        String ip = extractClientIp(http);
        String ua = http.getHeader("User-Agent");

        boolean ok = backupCodeService.consumeBackupCode(user, req.backupCode(), ip, ua);
        if (!ok) throw new IllegalArgumentException("Invalid backup code");

        String accessToken = tokenService.issueToken(user.getUsername(), 3600);
        return new VerifyMfaResponse(accessToken);
    }

    @Transactional
    public EnableMfaResponse enableMfa(String username, EnableMfaRequest req) {
        AppUser user = userRepository.findByUsername(username).orElseThrow();

        if (user.isMfaEnabled()) {
            throw new IllegalStateException("MFA already enabled");
        }

        String secret = totpService.generateSecret();
        user.setTotpSecret(secret);

        if (!totpService.verifyCode(secret, req.initialTotpCode(), 1)) {
            throw new IllegalArgumentException("Invalid initial TOTP code");
        }

        user.setMfaEnabled(true);
        userRepository.save(user);

        List<String> codes = backupCodeService.generateAndStoreNewCodesForUser(username, req.backupCodeCount() == null ? 10 : req.backupCodeCount());
        return new EnableMfaResponse(secret, codes);
    }

    @Transactional
    public RegenerateBackupCodesResponse regenerateBackupCodes(String username, Integer count) {
        AppUser user = userRepository.findByUsername(username).orElseThrow();
        if (!user.isMfaEnabled()) throw new IllegalStateException("MFA not enabled");
        List<String> codes = backupCodeService.generateAndStoreNewCodesForUser(username, count == null ? 10 : count);
        return new RegenerateBackupCodesResponse(codes);
    }

    private String extractClientIp(HttpServletRequest request) {
        String xff = request.getHeader("X-Forwarded-For");
        if (xff != null && !xff.isBlank()) {
            return xff.split(",")[0].trim();
        }
        return request.getRemoteAddr();
    }
}

