public class AuthController {

    private final AuthService authService;

    public AuthController(AuthService authService) {
        this.authService = authService;
    }

    @PostMapping("/register")
    public void register(@RequestBody LoginRequest req) {
        authService.register(req.username(), req.password());
    }

    @PostMapping("/login")
    public LoginResponse login(@RequestBody LoginRequest req) {
        return authService.login(req);
    }

    @PostMapping("/mfa/verify")
    public VerifyMfaResponse verifyTotp(@RequestBody VerifyMfaRequest req) {
        return authService.verifyTotp(req);
    }

    @PostMapping("/mfa/backup/verify")
    public VerifyMfaResponse verifyBackup(@RequestBody VerifyBackupCodeRequest req, HttpServletRequest http) {
        return authService.verifyBackupCode(req, http);
    }

    @PostMapping("/mfa/enable")
    public EnableMfaResponse enableMfa(@AuthenticationPrincipal(expression = "username") String username,
                                       @RequestBody EnableMfaRequest req) {
        return authService.enableMfa(username, req);
    }

    @PostMapping("/mfa/backup/regenerate")
    public RegenerateBackupCodesResponse regenerate(@AuthenticationPrincipal(expression = "username") String username,
                                                    @RequestParam(name = "count", required = false) Integer count) {
        return authService.regenerateBackupCodes(username, count);
    }
}

package com.example.mfa.web;

import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.time.Instant;

@RestControllerAdvice
public class ApiExceptionHandler {

    @ExceptionHandler(IllegalArgumentException.class)
    public ResponseEntity<ApiError> badRequest(IllegalArgumentException ex) {
        return ResponseEntity.status(HttpStatus.BAD_REQUEST).body(new ApiError(Instant.now().toString(), "BAD_REQUEST", ex.getMessage()));
    }

    @ExceptionHandler(IllegalStateException.class)
    public ResponseEntity<ApiError> conflict(IllegalStateException ex) {
        return ResponseEntity.status(HttpStatus.CONFLICT).body(new ApiError(Instant.now().toString(), "CONFLICT", ex.getMessage()));
    }

    @ExceptionHandler(Exception.class)
    public ResponseEntity<ApiError> serverError(Exception ex) {
        return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).body(new ApiError(Instant.now().toString(), "SERVER_ERROR", "Unexpected error"));
    }

    public record ApiError(String timestamp, String code, String message) {
    }
}

package com.example.mfa;

import com.example.mfa.user.AppUser;
import com.example.mfa.user.UserRepository;
import org.springframework.boot.CommandLineRunner;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.crypto.password.PasswordEncoder;

@Configuration
class SeedConfig {

    @Bean
    CommandLineRunner seed(UserRepository users, PasswordEncoder encoder) {
        return args -> {
            if (users.findByUsername("admin").isEmpty()) {
                AppUser u = new AppUser();
                u.setUsername("admin");
                u.setPasswordHash(encoder.encode("admin-password"));
                users.save(u);
            }
        };
    }
}

